import axios from "axios";

const BASE_URL = "http://localhost:8080";

// ================= AXIOS INSTANCE =================
const api = axios.create({
  baseURL: BASE_URL,
  headers: {
    "Content-Type": "application/json"
  }
});

// ================= REQUEST INTERCEPTOR =================
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token");

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// ================= RESPONSE INTERCEPTOR =================
api.interceptors.response.use(
  (response) => response,
  (error) => {
    console.error("API Error:", error.response?.data || error.message);

    if (error.response?.status === 401) {
      localStorage.removeItem("token");
      window.location.href = "/login";
    }

    if (error.response?.status === 403) {
      console.log("Forbidden - check role or token");
    }

    return Promise.reject(error);
  }
);

export default api;

//
// ================= AUTH (FIXED PATHS) =================
//

export const registerUser = (data) => api.post("/users/register", data);

export const loginUser = (data) => api.post("/users/login", data);

//
// ================= DASHBOARD =================
//

export const getDashboard = () => api.get("/admin/dashboard");

//
// ================= PRODUCTS =================
//

export const getItems = () => api.get("/items");

export const addItem = (item) => api.post("/admin/products", item);

export const updateItem = (id, item) =>
  api.put(`/admin/products/${id}`, item);

export const deleteItem = (id) =>
  api.delete(`/admin/products/${id}`);

//
// ================= ORDERS =================
//

export const getOrders = () => api.get("/admin/orders");

export const updateOrderStatus = (id, status) =>
  api.put(`/admin/orders/${id}/status?status=${status}`);
